module RefModule (
    input clk,
    input reset,
    input start,
    output reg done,
    output reg [2:0] channel
);

    reg [2:0] pipeline_reg;
    parameter IDLE = 3'b000, TRANSFER = 3'b001, COMPLETE = 3'b010;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            pipeline_reg <= IDLE;
            done <= 0;
            channel <= 3'b000;
        end else begin
            case (pipeline_reg)
                IDLE: begin
                    if (start) begin
                        pipeline_reg <= TRANSFER;
                        channel <= 3'b000;
                        done <= 0;
                    end
                end
                TRANSFER: begin
                    if (channel < 3'b111) begin
                        channel <= channel + 1;
                    end else begin
                        pipeline_reg <= COMPLETE;
                    end
                end
                COMPLETE: begin
                    done <= 1;
                    pipeline_reg <= IDLE;
                end
            endcase
        end
    end
endmodule
